import React, { useState } from 'react';
import '../styles/ActivityFoodLog.css';

const BAD_HABITS = [
  {
    id: 'skipped_workout',
    title: 'Skipped workout',
    description: 'Did not exercise today',
    icon: '/workout.png',
    penalties: { energy: -8, discipline: -6, xpPenalty: 15 },
    tags: [{ label: '-8 Energy', color: '#60a5fa' }, { label: '-6 Discipline', color: '#a78bfa' }, { label: '-15 XP', color: '#f87171' }],
  },
  {
    id: 'ate_junk',
    title: 'Ate junk food',
    description: 'Consumed unhealthy food today',
    icon: '/no-sugar.png',
    penalties: { hp: -5, discipline: -8, xpPenalty: 10 },
    tags: [{ label: '-5 HP', color: '#f87171' }, { label: '-8 Discipline', color: '#a78bfa' }, { label: '-10 XP', color: '#f87171' }],
  },
  {
    id: 'poor_sleep',
    title: 'Poor sleep',
    description: 'Slept less than 6 hours',
    icon: '/sleeping-mask.png',
    penalties: { hp: -4, energy: -12, xpPenalty: 10 },
    tags: [{ label: '-4 HP', color: '#f87171' }, { label: '-12 Energy', color: '#60a5fa' }, { label: '-10 XP', color: '#f87171' }],
  },
  {
    id: 'no_water',
    title: 'Forgot to drink water',
    description: 'Drank less than 1L today',
    icon: '/plastic-bottle.png',
    penalties: { hp: -6, energy: -5, xpPenalty: 5 },
    tags: [{ label: '-6 HP', color: '#f87171' }, { label: '-5 Energy', color: '#60a5fa' }, { label: '-5 XP', color: '#f87171' }],
  },
  {
    id: 'stress',
    title: 'High stress day',
    description: 'Did not manage stress well',
    icon: '/health.png',
    penalties: { hp: -5, energy: -6, discipline: -4, xpPenalty: 8 },
    tags: [{ label: '-5 HP', color: '#f87171' }, { label: '-6 Energy', color: '#60a5fa' }, { label: '-4 Discipline', color: '#a78bfa' }],
  },
  {
    id: 'skipped_stretch',
    title: 'No stretching or warmup',
    description: 'Skipped warmup/cooldown',
    icon: '/exercising.png',
    penalties: { energy: -4, discipline: -3, xpPenalty: 5 },
    tags: [{ label: '-4 Energy', color: '#60a5fa' }, { label: '-3 Discipline', color: '#a78bfa' }],
  },
];

const GOOD_ACTIVITIES = [
  { id: 'logged_meal',   title: 'Logged a healthy meal',   icon: '/healthy-food.png',      xp: 10 },
  { id: 'drank_water',   title: 'Drank 2L+ of water',      icon: '/plastic-bottle.png',    xp: 15 },
  { id: 'walked',        title: 'Walked 5,000+ steps',     icon: '/footprint.png',          xp: 20 },
  { id: 'cooked_home',   title: 'Cooked a meal at home',   icon: '/no-sugar.png',           xp: 12 },
];

const ActivityFoodLog = ({ onBadHabit }) => {
  const [reported, setReported]   = useState({});
  const [flash, setFlash]         = useState(null);
  const [goodDone, setGoodDone]   = useState({});
  const [goodFlash, setGoodFlash] = useState(null);
  const [confirmHabit, setConfirmHabit] = useState(null); // habit awaiting confirm

  const handleConfirm = (habit) => {
    if (reported[habit.id]) return;
    setReported(prev => ({ ...prev, [habit.id]: true }));
    if (onBadHabit) onBadHabit(habit.penalties);
    setFlash({ id: habit.id, label: `Penalties applied!` });
    setTimeout(() => setFlash(null), 2000);
    setConfirmHabit(null);
  };

  const handleGoodActivity = (act) => {
    if (goodDone[act.id]) return;
    setGoodDone(prev => ({ ...prev, [act.id]: true }));
    setGoodFlash({ id: act.id, xp: act.xp });
    setTimeout(() => setGoodFlash(null), 2000);
  };

  return (
    <div className="afl-page">
      {/* Confirm modal */}
      {confirmHabit && (
        <div className="afl-modal-overlay" onClick={() => setConfirmHabit(null)}>
          <div className="afl-modal" onClick={e => e.stopPropagation()}>
            <div className="afl-modal-icon">
              <img src={confirmHabit.icon} alt="" style={{width:48,height:48,objectFit:'contain'}} />
            </div>
            <div className="afl-modal-title">Report bad habit?</div>
            <div className="afl-modal-desc">"{confirmHabit.title}" will apply these penalties to your stats:</div>
            <div className="afl-modal-tags">
              {confirmHabit.tags.map((t, i) => (
                <span key={i} className="afl-modal-tag" style={{ color: t.color, borderColor: t.color + '44', background: t.color + '18' }}>{t.label}</span>
              ))}
            </div>
            <div className="afl-modal-actions">
              <button className="afl-btn-cancel" onClick={() => setConfirmHabit(null)}>Cancel</button>
              <button className="afl-btn-confirm" onClick={() => handleConfirm(confirmHabit)}>Yes, report it</button>
            </div>
          </div>
        </div>
      )}

      <div className="afl-inner">

        {/* Header */}
        <div className="afl-header">
          <div className="afl-header-left">
            <div className="afl-header-icon">
              <img src="/healthy-food.png" alt="" style={{width:38,height:38,objectFit:'contain'}} />
            </div>
            <div>
              <div className="afl-header-title">Activity & Food Log</div>
              <div className="afl-header-sub">Track your habits — good and bad — to keep your stats honest</div>
            </div>
          </div>
        </div>

        <div className="afl-grid">

          {/* ── Bad Habits ── */}
          <div className="afl-section">
            <div className="afl-section-header">
              <div className="afl-section-title bad">
                <div className="afl-section-dot red" />
                Bad Habits
              </div>
              <div className="afl-section-badge red">{Object.keys(reported).length} reported today</div>
            </div>
            <div className="afl-section-desc">
              Be honest with yourself. Reporting bad habits keeps your stats accurate and motivates you to do better tomorrow.
            </div>
            <div className="afl-list">
              {BAD_HABITS.map(habit => (
                <div
                  key={habit.id}
                  className={`afl-item ${reported[habit.id] ? 'afl-reported' : ''}`}
                >
                  {flash && flash.id === habit.id && (
                    <div className="afl-flash red">{flash.label}</div>
                  )}
                  <img src={habit.icon} alt="" style={{width:32,height:32,objectFit:'contain',flexShrink:0}} />
                  <div className="afl-item-body">
                    <div className="afl-item-title">{habit.title}</div>
                    <div className="afl-item-desc">{habit.description}</div>
                    <div className="afl-item-tags">
                      {habit.tags.map((t, i) => (
                        <span key={i} className="afl-tag" style={{ color: t.color, borderColor: t.color + '44', background: t.color + '18' }}>{t.label}</span>
                      ))}
                    </div>
                  </div>
                  <button
                    className={`afl-report-btn ${reported[habit.id] ? 'reported' : ''}`}
                    onClick={() => !reported[habit.id] && setConfirmHabit(habit)}
                    disabled={reported[habit.id]}
                  >
                    {reported[habit.id] ? '✓ Reported' : 'Report'}
                  </button>
                </div>
              ))}
            </div>
          </div>

          {/* ── Good Activities ── */}
          <div className="afl-section">
            <div className="afl-section-header">
              <div className="afl-section-title good">
                <div className="afl-section-dot green" />
                Good Activities
              </div>
              <div className="afl-section-badge green">{Object.keys(goodDone).length} logged today</div>
            </div>
            <div className="afl-section-desc">
              Log positive habits to earn bonus XP on top of your challenges.
            </div>
            <div className="afl-list">
              {GOOD_ACTIVITIES.map(act => (
                <div key={act.id} className={`afl-item ${goodDone[act.id] ? 'afl-good-done' : ''}`}>
                  {goodFlash && goodFlash.id === act.id && (
                    <div className="afl-flash green">+{goodFlash.xp} XP earned!</div>
                  )}
                  <img src={act.icon} alt="" style={{width:32,height:32,objectFit:'contain',flexShrink:0}} />
                  <div className="afl-item-body">
                    <div className="afl-item-title">{act.title}</div>
                    <div className="afl-item-tags">
                      <span className="afl-tag" style={{ color:'#34d399', borderColor:'#34d39944', background:'#34d39918' }}>+{act.xp} XP</span>
                    </div>
                  </div>
                  <button
                    className={`afl-log-btn ${goodDone[act.id] ? 'logged' : ''}`}
                    onClick={() => handleGoodActivity(act)}
                    disabled={goodDone[act.id]}
                  >
                    {goodDone[act.id] ? '✓ Logged' : 'Log it'}
                  </button>
                </div>
              ))}
            </div>

            {/* Daily summary */}
            <div className="afl-summary">
              <div className="afl-summary-title">Today's Honesty Score</div>
              <div className="afl-summary-desc">
                {Object.keys(reported).length === 0 && Object.keys(goodDone).length === 0
                  ? 'Nothing logged yet. Be honest about your day!'
                  : Object.keys(reported).length === 0
                  ? '🌟 Great — no bad habits reported!'
                  : `You reported ${Object.keys(reported).length} bad habit${Object.keys(reported).length > 1 ? 's' : ''} today. Honesty builds discipline!`
                }
              </div>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
};

export default ActivityFoodLog;
